args.sparql:
SELECT ?country ?countryLabel ?pm ?pmLabel ?mother ?motherLabel ?father ?fatherLabel ?motherProfession ?motherProfessionLabel ?fatherProfession ?fatherProfessionLabel
WHERE {
  ?country wdt:P463 wd:Q142;
          rdfs:label ?countryLabel.
  FILTER(LANG(?countryLabel) = "en").
  ?country wdt:P35 ?pm;
          rdfs:label ?pmLabel.
  FILTER(LANG(?pmLabel) = "en").
  ?pm wdt:P25 ?mother;
          rdfs:label ?motherLabel.
  FILTER(LANG(?motherLabel) = "en").
  ?pm wdt:P22 ?father;
          rdfs:label ?fatherLabel.
  FILTER(LANG(?fatherLabel) = "en").
  ?mother wdt:P106 ?motherProfession;
          rdfs:label ?motherProfessionLabel.
  FILTER(LANG(?motherProfessionLabel) = "en").
  ?father wdt:P106 ?fatherProfession;
          rdfs:label ?fatherProfessionLabel.
  FILTER(LANG(?fatherProfessionLabel) = "en").
}
